var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"시체가 일어나는 경우?","JPN":"死体が起き上がる場合？","ENG":"A corpse rising from the dead?","TWN":"屍體復活？"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"너도 알겠지만, 침식 지대에서 사람이 죽으면 대부분 침식체가 돼.","JPN":"あなたも知っているとおり、侵食地帯で人が死ぬとだいたいは侵食体になるわ。","ENG":"You already know this, but when someone dies in a Corrupted Area, they usually turn into a C.O.","TWN":"你也知道，在侵蝕地帶人死後大多數會變成侵蝕體。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"시체가 형태를 유지한 채 침식체가 되는 경우가 있긴 하지만.","JPN":"死体が形を維持したまま侵食体になる場合もあるけど。","ENG":"There are cases where the body retains its form after becoming a C.O...","TWN":"雖然有時候屍體變成侵蝕體後，會保持原來的狀態。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"흔한 경우는 아니지.","JPN":"滅多にないわね。","ENG":"But it's rare.","TWN":"但這種情況並不常見。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"네크로멘시 능력, 혹은 그 능력을 가진 아티팩트를 사용했을 경우.","JPN":"ネクロマンシー能力、あるいはその能力を持っているアーティファクトを使用した場合。","ENG":"Unless necromancy is involved, or an Artifact with that power is being used.","TWN":"只有在使用死靈術能力，或使用擁有該能力的神器時，"},"stage":{"bg":"CASTLE_03","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HOLY_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"죽은 자를 살리는 비술을 알고 있는 경우.","JPN":"死んだ者を蘇らせる秘術を知っている場合。","ENG":"Or if someone possesses the knowledge of resurrection magic.","TWN":"或是復活死者的秘術。"},"stage":{"bg":"SS_ESPR_06","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"또 다른 경우는 너도 알고 있는…….","JPN":"もう1つの場合は、あなたも知っているように……","ENG":"And of course, there's another possibility you're well aware–","TWN":"還有另一個情況你應該也知道……"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"아뇨. 그 정도면 충분해요.","JPN":"いいえ。そのくらいで十分です。","ENG":"No, that's enough.","TWN":"不，這樣就夠了。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"결론은, 진짜 유령이나 귀신 같은 건 없는 거니까.","JPN":"結論は、本物の幽霊とかお化けはいないということですから。","ENG":"The point is, there are no actual ghosts or evil spirits.","TWN":"結論是，根本沒有真正的幽靈或鬼怪。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"그러다가 진짜 귀신이 나타나면 어쩌려고 그럴까?","JPN":"そんなこと言って本物のお化けが出たらどうするの？","ENG":"What if a real ghost shows up?","TWN":"要是這樣真的引來鬼魂怎麼辦？"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"진짜 귀신이 어딨어요. 다 침식체를 잘못 본 거지.","JPN":"お化けなんていませんよ。全部侵食体の見間違いでしょう。","ENG":"There's no such thing. People just mistake C.O.s for ghosts.","TWN":"哪裡會有真正的鬼啊，肯定是錯看成侵蝕體了。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"물론, 그런 겁쟁이들이 많을수록 저는 좋죠.","JPN":"もちろん、そんな臆病者が多ければ多いほど私にはいいことです。","ENG":"But hey, the more cowards there are, the better it is for me.","TWN":"膽小鬼越多越好。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그래야 돈을 더 많이 벌 테니.","JPN":"もっと稼げますしね。","ENG":"Just means more profit.","TWN":"這樣才能賺更多的錢。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"그래. 퇴마사의 신조가 그 정도는 돼야 먹고 살지.","JPN":"そう。そのくらいの信条でないと、エクソシストとしては生きていけないわね。","ENG":"Well, an exorcist needs to have that kind of mindset to make a living.","TWN":"沒錯，驅魔師至少要有這種程度的信念才能生存下去。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"무슨 섭섭한 말씀을.","JPN":"何を他人事のように。","ENG":"Oh, come on.","TWN":"你說的這些話真讓人傷心。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"아, 만약 진짜 혹시라도 귀신이 있으면 하고 싶은 게 있긴 해요.","JPN":"あ、もし本当にお化けがいるならやってみたいことはあります。","ENG":"By the way, if ghosts were actually real, there's something I'd like to try.","TWN":"啊，如果真的有鬼的話，我倒是有些想做的事情。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L30_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"죽기 전에 숨겨둔 유산이나 재물을 뜯어내는 거죠.","JPN":"生前に隠しておいた遺産とか財産を巻き上げてやるんです。","ENG":"I'd get them to cough up whatever treasures they stashed away before they died.","TWN":"在他們死之前，把他們藏起來的遺產或財物榨乾。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"어차피 걔네는 현세의 물건은 필요 없을 거잖아요.","JPN":"どうせあいつらに現世のものは要らないでしょう？","ENG":"I mean, they don't need worldly possessions anymore, do they?","TWN":"反正這些東西他們也帶不走。"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"흐, 흐흐흐…… 생각만 해도 군침이…….","JPN":"ふ、ふふふ……考えただけでも笑いが……","ENG":"Heh... Hehehe... Just thinking about it makes my mouth water...","TWN":"嘿，嘿嘿嘿……光是想想就讓人流口水……"},"stage":{"bg":"STORE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"여기서 뭘 하고 있는 건가?","JPN":"ここで何をしているのかね？","ENG":"What are you doing over there?","TWN":"你在這裡做什麼？"},"stage":{"bg":"STORE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L39_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"히이익!","JPN":"ひいいっ！","ENG":"Eeeep!","TWN":"哎呀！"},"stage":{"bg":"STORE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"화장실에 다녀온다더니, 1시간이 지나도록 소식이 없어서 말일세.","JPN":"用を足しに行ってから、小1時間も戻らないのでね。","ENG":"You said you were going to the bathroom, but it's been an hour.","TWN":"說是去上廁所，結果一個小時過去了還沒消息。"},"stage":{"bg":"STORE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"아, 출발하기 전에 확인해야 할 것들이 있어서 말이죠.","JPN":"あ、出発する前に確認しないといけないものがありまして。","ENG":"Oh, I just needed to check a few things before we head out.","TWN":"啊，出發之前有些事情需要確認一下。"},"stage":{"bg":"STORE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"계약서에도 나와 있지만, 모든 비용은 의뢰인이 부담합니다.","JPN":"契約書にも記載されているとおり、すべての費用は依頼人の負担となります。","ENG":"As per the contract, all expenses are covered by the client.","TWN":"雖然合約上也寫了，但所有費用都由委託人承擔。"},"stage":{"bg":"STORE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"괜찮네.","JPN":"問題ない。","ENG":"That's fine.","TWN":"沒問題。"},"stage":{"bg":"STORE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"태스크포스를 부르는 것에 비하면 푼돈 수준이니까.","JPN":"タスクフォースを呼ぶよりはずっと安いからな。","ENG":"Compared to calling in a TASKFORCE, it's a bargain.","TWN":"比起找特遣勢力，這點錢算不了什麼。"},"stage":{"bg":"STORE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"흐, 흐흐. 그렇죠?","JPN":"ふ、ふふ。そうでしょう？","ENG":"Heh… hehe. Right?","TWN":"哼，哼哼。是吧？"},"stage":{"bg":"STORE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"태스크포스를 부르는 것보다는 훨씬 남는 장사……가 아니라 퇴마니까요.","JPN":"タスクフォースを呼ぶよりはずっと安い商売……じゃなくて、退魔ですから。","ENG":"It's much more profitable– I mean, this is an exorcism so there's no need to call in a TASKFORCE.","TWN":"比起找特遣勢力，這可是更划算的生意……不，驅魔儀式。"},"stage":{"bg":"STORE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"자, 얼른 출발하시죠.","JPN":"さあ、早く出発しましょう。","ENG":"All right, let's get going.","TWN":"好，趕快出發吧。"},"stage":{"bg":"STORE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"지하 묘지엔 음기가 강해서, 낮에 미리 작업을 해두지 않으면 곤란해요.","JPN":"地下墓地は陰気が強いので、昼間にあらかじめ作業しておきませんと。","ENG":"The underground crypt is thick with negative energy. If we don't start working during the day, things could get tricky.","TWN":"地下墓地陰氣很重，如果不在白天提前做好準備會很麻煩。"},"stage":{"bg":"STORE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"차를 준비해 놨네.","JPN":"車を用意してある。","ENG":"I brought my car.","TWN":"車已經準備好了。"},"stage":{"bg":"STORE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"영지까지 가는 길 편안하게 가세나.","JPN":"領地までくつろぐといい。","ENG":"We'll have a comfortable ride to the estate.","TWN":"路上小心。"},"stage":{"bg":"STORE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"야호!","JPN":"やっほ～！","ENG":"Woohoo!","TWN":"呀喝！"},"stage":{"bg":"STORE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"……가 아니라, 형제님의 은혜에 보답하도록 하겠습니다.","JPN":"……じゃなくて、ブラザーのお心遣いにお応えできるよう頑張ります。","ENG":"...I mean, I am grateful for your generosity, Brother Ludwig.","TWN":"我會報答弟兄的恩情的。"},"stage":{"bg":"STORE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"별일 없을 거예요. 끊을게요.","JPN":"どうってことないと思いますよ。もう切りますね。","ENG":"Everything should be fine. Hanging up now.","TWN":"不會有事的，我先掛囉。"},"stage":{"bg":"STORE","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"또 자기 할 말만 하고 끊어버렸네.","JPN":"また一方的に話して切る。","ENG":"Hung up after saying her piece again...","TWN":"又自顧自地說完就掛了。"},"stage":{"bg":"CHURCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"남의 말은 끝까지 들으라고 그렇게 말했는데.","JPN":"人の話は最後まで聞きなさいってあれほど言っているのに。","ENG":"I keep telling her to hear people out before interrupting.","TWN":"我不是說了要聽別人把話說完嗎？"},"stage":{"bg":"CHURCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"뭐, 애초에 다루기 어려운 애였으니까.","JPN":"まあ、そもそも扱いづらい子だったわ。","ENG":"Well, she's always been hard to handle.","TWN":"也是，她本來就耳朵很硬。"},"stage":{"bg":"CHURCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"그럼 루시아, 이번에도 안 들키고 무사히 끝내길 바랄게.","JPN":"じゃあ、ルシア。今回もバレずに無事終わらせられますように。","ENG":"Let's hope you don't get caught this time either, Lucia.","TWN":"露西卡，這次也希望你能不被發現，順利完成任務。"},"stage":{"bg":"CHURCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"몰래 찍은 네 사진들, 비싼 값에 사는 사람들이 많더라고.","JPN":"こっそり撮影したあなたの写真、高く買ってくれる人が多いの。","ENG":"By the way, a lot of people are willing to pay good money for those secret photos of you.","TWN":"偷拍你的照片，有很多人願意出高價買呢。"},"stage":{"bg":"CHURCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"나도 보탬이 되려고 노력하는 거니까, 이해해 줄 수 있지?","JPN":"私も役に立ちたくて頑張ってるんだから、理解してくれるわね？","ENG":"I'm just trying to do my part. You understand, right?","TWN":"我也在努力幫忙，你能理解吧？"},"stage":{"bg":"CHURCH","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};